import React, { useState } from 'react';
import './EditMaterial.css';

const EditMaterial = ({ material, handleUpdate }) => {
  const [formData, setFormData] = useState({
    name: material.name || '',
    description: material.description || '',
    field: material.field || '',
    unit_of_measure: material.unit_of_measure || '',
    extras: material.extras || '',
    shelflife: material.shelflife || '',
    minstock: material.minstock || '',
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prevFormData) => ({
      ...prevFormData,
      [name]: value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    handleUpdate({formData });
  };

  return (
    <div className="edit-material-container">
      <h2 className="edit-material-heading">Edit Material</h2>
      <form className="edit-material-form" onSubmit={handleSubmit}>
        <div className="form-group">
          <CustomInput
            label="Name"
            name="name"
            value={formData.name}
            onChange={handleInputChange}
          />
          <CustomInput
            label="Description"
            name="description"
            value={formData.description}
            onChange={handleInputChange}
          />
          <CustomInput
            label="Field"
            name="field"
            value={formData.field}
            onChange={handleInputChange}
          />
          <CustomInput
            label="Unit of Measure"
            name="unit_of_measure"
            value={formData.unit_of_measure}
            onChange={handleInputChange}
          />
          <CustomInput
            label="Extra Characteristics"
            name="extras"
            type="number"
            value={formData.extras}
            onChange={handleInputChange}
          />
          <CustomInput
            label="Shelf Life"
            name="shelflife"
            type="number"
            value={formData.shelflife}
            onChange={handleInputChange}
          />
          <CustomInput
            label="Minimum Stock"
            name="minstock"
            type="number"
            value={formData.minstock}
            onChange={handleInputChange}
          />
        </div>
        <button type="submit" className="edit-material-btn">Update</button>
      </form>
    </div>
  );
};

const CustomInput = ({ label, ...restProps }) => {
  return (
    <div className="form-group">
      <label htmlFor={restProps.name}>{label}:</label>
      <input {...restProps} />
    </div>
  );
};

export default EditMaterial;
